def transform(res):
    x, y, w, h, conf1, conf2 = res[:]
    x1 = x - w/2
    y1 = y - h/2
    x2 = x + w/2
    y2 = y + h/2
    return [x1, y1, x2, y2, conf1, conf2]

def letterbox(img, target_dim) -> tuple[float, nt.NDArray, int, int]:
    original_h, original_w = img.shape[:2]
    scale = None
    if original_h > original_w:
        scale = target_dim/original_h
    else:
        scale = target_dim/original_w
    new_size = (int(original_w * scale), int(original_h * scale))
    rescaled = cv.resize(img, new_size, interpolation=cv.INTER_LINEAR)
    pad_w = target_dim - new_size[0]
    pad_h = target_dim - new_size[1]
    padded = cv.copyMakeBorder(
        rescaled,
        math.ceil(pad_h / 2),
        math.floor(pad_h / 2),
        math.ceil(pad_w / 2),
        math.floor(pad_w / 2),
        cv.BORDER_CONSTANT,
        value=(114, 114, 114)
    )
    return scale, padded, math.ceil(pad_w/2), math.ceil(pad_h/2)

def nms(x1, y1, x2, y2, conf):
    areas = (x2 - x1 + 1) * (y2 - y1 + 1)
    order = conf.argsort()[::-1]

    keep: list[int] = []
    while order.size > 0:
        i = int(order[0])
        keep.append(i)
        if order.size == 1:
            break

        xx1 = np.maximum(x1[i], x1[order[1:]])        
        yy1 = np.maximum(y1[i], y1[order[1:]])
        xx2 = np.minimum(x2[i], x2[order[1:]])
        yy2 = np.minimum(y2[i], y2[order[1:]])

        w = np.maximum(0.0, xx2 - xx1 + 1)
        h = np.maximum(0.0, yy2 - yy1 + 1)
        inter = w * h
        iou = inter / (areas[i] + areas[order[1:]] - inter + 1e-9)

        inds = np.where(iou <= 0.5)[0]
        order = order[inds + 1]
    stay = np.zeros((conf.shape[0]), dtype=np.bool)
    stay[keep] = True
    return stay

def recover(x1, y1, x2, y2, scale, px, py):
    x1 = x1 - px
    y1 = y1 - py
    x2 = x2 - px
    y2 = y2 - py
    return (x1/scale, y1/scale, x2/scale, y2/scale)

class Camera(Node):
    def __init__(self):
        super().__init__('camera')
        self.create_subscription(Point, '/crane_position', self.update_crane_position, 20)
        self.payload_publisher = self.create_publisher(Point, '/payload_position', 20)
        self.drop_publisher = self.create_publisher(Point, '/drop_position', 20)
        self.coord_offset = (0, 0)
        self.payload_coord = (0, 0)
        self.payload_y = 0
        self.calibrate_service = self.create_service(Empty, '/calibrate_offset', self.calibrate_offset)
        self.timer = self.create_timer(1/10, self.timer_callback)
        self.vid_cap = cv.VideoCapture(1)
        cw = int(self.vid_cap.get(cv.CAP_PROP_FRAME_WIDTH))
        ch = int(self.vid_cap.get(cv.CAP_PROP_FRAME_HEIGHT))
        self.ncm, self.roi = cv.getOptimalNewCameraMatrix(mtx, dist, (cw, ch), 1, (cw, ch))
        #self.vid_cap = cv.VideoCapture('../../raw-dataset-2/11_raw.mp4')
        #self.vid_cap.set(cv.CAP_PROP_FOURCC, cv.VideoWriter_fourcc('M','J','P','G'))
        if not self.vid_cap.isOpened():
            raise RuntimeError("Camera is not found")
        so = ort.SessionOptions()
        so.graph_optimization_level = ort.GraphOptimizationLevel.ORT_ENABLE_ALL
        self.sess = ort.InferenceSession(ONNX_SOURCE, sess_options=so, providers=["AzureExecutionProvider", "CPUExecutionProvider"])
    
    def calibrate_offset(self, req, res):
        print(f'calibrate {self.payload_coord}')
        self.coord_offset = self.payload_coord
        return res

    def do_inference(self, img, scale, px, py):
        input_name = self.sess.get_inputs()[0].name
        out = self.sess.run(None, { input_name: img })
        out = np.squeeze(out[0])
        x1, y1, x2, y2, conf2, conf1 = transform(out)

        #print(np.max(conf1), np.max(conf2))
        res = []
        '''
        for conf in [conf1, conf2]:
            mask_thresh = conf > CONFIDENCE_THRESH
            #mask_nms = nms(x1, y1, x2, y2, conf)
            #mask = np.bitwise_and(mask_thresh, mask_nms)
            mask = mask_thresh
            # Pick best representation
            if np.any(mask):
                best_idx = np.argmax(conf * mask)
                xx1, yy1, xx2, yy2 = recover(
                    x1[best_idx], 
                    y1[best_idx], 
                    x2[best_idx], 
                    y2[best_idx], 
                    scale, 
                    px, 
                    py)
                res.append((xx1, yy1, xx2, yy2, conf[best_idx]))
            else:
                res.append(None)
        '''
        for conf in [conf1, conf2]:
            best = np.argmax(conf)
            if conf[best] < CONFIDENCE_THRESH:
                res.append(None)
                continue
            xx1, yy1, xx2, yy2 = recover(
                x1[best], 
                y1[best], 
                x2[best], 
                y2[best], 
                scale, 
                px, 
                py)
            res.append((xx1, yy1, xx2, yy2, conf[best]))

        return res

    def validate(self, payload_bb, drop_bb, img):
        px1, py1, px2, py2, _ = payload_bb
        dx1, dy1, dx2, dy2, _ = payload_bb
        px1, py1, px2, py2, dx1, dy1, dx2, dy2 = map(int, [px1, py1, px2, py2, dx1, dy1, dx2, dy2])
        drop = img[dy1:dy2, dx1:dx2]
        payload = img[py1:py2, px1:px2]
        hsv = cv.cvtColor(payload, cv.COLOR_BGR2HSV)
        blur = cv.GaussianBlur(payload, (3, 3), 0, None)
        gray = cv.cvtColor(blur, cv.COLOR_BGR2GRAY)
        contours, hierarchy = cv.findContours(gray, cv.RETR_EXTERNAL, cv.CHAIN_APPROX_SIMPLE)
        for cnt in contours:
            area = cv.contourArea(cnt)
            if area < 1000:
                continue
            canvas = np.zeros_like(payload)
            cv.drawContours(canvas, [cnt], 0, (255, 255, 255), cv.FILLED)
            mean_sat = np.mean(np.bitwise_and(canvas, hsv)[:,:,1])
            mean_val = np.mean(np.bitwise_and(canvas, hsv)[:,:,2])
            #print(mean_sat, mean_val)
        return (payload_bb, drop_bb)

    def timer_callback(self):
        ok, frame = self.vid_cap.read()
        if cv.waitKey(1) == ord('q'):
            cv.destroyAllWindows()
            rclpy.shutdown()
        if not ok:
            self.get_logger().warning("Frame Skipped / Feedback stopped")
            rclpy.shutdown()
            return
        # cv.imshow('Original', frame)

        #ncm, roi = cv.getOptimalNewCameraMatrix(mtx, dist, (original_w, original_h), 1, (original_w, original_h))
        undist = cv.undistort(frame, mtx, dist, None, self.ncm)
        bx, by, bw, bh = self.roi
        undist = undist[by:by+bh, bx:bx+bw]

        scale, padded, px, py = letterbox(undist, IMG_SIZE)   
        #cv.imshow('Padded', padded)
        prep = cv.cvtColor(padded, cv.COLOR_BGR2RGB)
        prep = prep.astype(np.float32) / 255.0
        prep = np.transpose(prep, (2, 0, 1))
        prep = np.expand_dims(prep, axis=0)
        start = time.time()
        payload_bb, drop_bb = self.do_inference(prep, scale, px, py)
        print("Inference:", time.time() - start)
        # if payload_bb is not None and drop_bb is not None:
        #    payload_bb, drop_bb = self.validate(payload_bb, drop_bb, undist)
        # print(payload_bb, drop_bb)
        if payload_bb is not None:
            a = int(payload_bb[0])
            b = int(payload_bb[1])
            c = int(payload_bb[2])
            d = int(payload_bb[3])
            conf = payload_bb[4]
            ix = (a + c) / 2
            iy = (b + d) / 2
            # imh = undist.shape[0]
            imw = undist.shape[1]
            # cx = ncm[0][2]
            # cy = ncm[1][2]
            # fx = ncm[0][0]
            # fy = ncm[1][1]
            # cam_height = PAYLOAD_SIZE * fx / ((c - a))
            # cam_height = 0.82
            # xw = (ux - cx) * cam_height / fx
            # yw = (uy - cy) * cam_height / fx
            # cv.circle(undist, (int(cx), int(cy)), 5, (0, 0, 255), cv.FILLED)
            # xc = (iw / imw) * RW_W
            # yc = (ih / imh) * RW_W
            # print(f'{iw}/{imw} {ih}/{imh}')
            # print(xc, yc)
            #cv.putText(undist, f"{cx}|{cy}")
            cv.circle(undist, (int(ix), int(iy)), 5, (255, 0, 0), cv.FILLED)
            self.payload_coord = (a, b)
            ix = ix - self.coord_offset[0] 
            iy = iy - self.coord_offset[1] 
            ix *= CAMERA_HEIGHT
            iy *= CAMERA_HEIGHT
            undist = cv.rectangle(undist, (a, b), (c, d), (255, 0, 0), 2)
            msg = Point()
            msg.x = float(ix * RW_W / imw)
