            undist = cv.rectangle(undist, (a, b), (c, d), (0, 0, 255), 2)
            ix = ix - self.coord_offset[0] 
            iy = iy - self.coord_offset[1] 
            msg = Point()
            msg.x = float(ix * RW_W / imw)
            msg.y = float(iy * RW_W / imw)
